/* SESSION_1B7_LOADED - Silence Session 0N sort-log console noise  */
/* ============================================================ */
/* The Session 0N sorter (line ~691) logs "Sorted N cards by SNo" */
/* on every re-sort. Because its MutationObserver re-fires on the */
/* sorter's own re-append, the message repeats ~10x/sec forever.  */
/* This patch suppresses ONLY that specific log message. All other*/
/* console output is passed through untouched. Idempotent on      */
/* re-deploy (unwraps a prior wrap before re-wrapping).           */
/* ============================================================ */
(function(){
  window.SESSION_1B7_LOADED = true;

  // If a prior 1B.7 wrap exists, restore the true original first (idempotent).
  if (window._pps_origConsoleLog) {
    console.log = window._pps_origConsoleLog;
  }

  var orig = console.log;
  window._pps_origConsoleLog = orig;

  var SUPPRESS_PREFIX = "[Session 0N] Sorted";

  console.log = function() {
    if (arguments.length &&
        typeof arguments[0] === "string" &&
        arguments[0].indexOf(SUPPRESS_PREFIX) === 0) {
      return; // drop only the noisy 0N "Sorted N cards by SNo" line
    }
    return orig.apply(console, arguments);
  };

  // Mark the wrapper so we can detect it if needed.
  console.log.__pps1b7wrapped = true;

  // Use the ORIGINAL log for our own confirmation so it always shows.
  orig.call(console, "[Session 1B.7] Session 0N 'Sorted N cards by SNo' log suppressed. Other logs unaffected.");
})();


/* SESSION_1B6_LOADED - Fix search-result sidebar click not opening popup */
/* ============================================================ */
/* ROOT CAUSE: The Session 1B.3 card-click delegation is attached to      */
/* #cards in BUBBLE phase. When a search result is clicked, the base      */
/* app's blur/re-render (search input losing focus) re-renders #cards     */
/* BEFORE the bubble handler runs, detaching the clicked node so the      */
/* handler misses it. Marker clicks are unaffected (wired separately).    */
/*                                                                        */
/* FIX: A CAPTURE-phase document click listener fires at the very start   */
/* of the event lifecycle -- before any re-render -- reads the sno while  */
/* the DOM is still intact, and calls window.showTempleInPanel(sno),      */
/* mirroring the working marker path. Preserves existing exclusions       */
/* (sthala links, nayanmar chips). Does NOT stopPropagation, so existing  */
/* handlers still run; showTempleInPanel is idempotent so a double-call   */
/* is harmless. Idempotent install (removes any prior 1B.6 listener).     */
/* ============================================================ */
(function(){
  window.SESSION_1B6_LOADED = true;
  var log = window._pps_origConsoleLog || console.log;
  log.call(console, "[Session 1B.6] Installing capture-phase card-click handler for search-result fix...");

  // Idempotent: remove any prior 1B.6 handler before re-installing.
  if (window._pps1b6ClickHandler) {
    document.removeEventListener("click", window._pps1b6ClickHandler, true);
  }

  window._pps1b6ClickHandler = function(e) {
    var t = e.target;
    if (!t || !t.closest) return;

    // --- Preserve existing exclusions (mirror Session 1B.3 behavior) ---
    // 1. Real hyperlinks (except our sthala-purana enrich link) should work normally.
    var anchor = t.closest("a[href]");
    if (anchor && !anchor.classList.contains("pps-enrich-sthala-link")) {
      return; // let the link navigate; do not hijack
    }
    // 2. Nayanmar chips have their own behavior.
    if (t.closest(".pps-nayanmar-chip")) {
      return;
    }

    // --- Find the clicked temple card ---
    var card = t.closest(".card[data-sno]");
    if (!card) return;

    // Read sno SYNCHRONOUSLY now, while the DOM node is still attached
    // (before any blur/re-render can detach it).
    var snoRaw = card.getAttribute("data-sno");
    var sno = parseInt(snoRaw, 10);
    if (!sno) return;

    if (typeof window.showTempleInPanel === "function") {
      // Defer the actual open by a microtask-ish tick so we let the base
      // app's blur/re-render happen first, THEN open the panel with the
      // sno we already captured. This guarantees the panel opens and is
      // not immediately clobbered by a re-render.
      var capturedSno = sno;
      setTimeout(function(){
        try {
          window.showTempleInPanel(capturedSno);
        } catch (err) {
          (window._pps_origConsoleLog || console.log).call(
            console, "[Session 1B.6] showTempleInPanel error: " + err.message);
        }
      }, 0);
    }
  };

  document.addEventListener("click", window._pps1b6ClickHandler, true); // capture phase

  log.call(console, "[Session 1B.6] Capture-phase handler installed. Search-result clicks now open the popup.");
})();


/* SESSION_1B8_LOADED - Stop Session 0N re-sort loop (fixes click-eating) */
/* ====================================================================== */
/* ROOT CAUSE: Session 0N sortCardsBySno() re-appends every card, which   */
/* is itself a childList mutation that re-triggers 0N's own reorderObserver*/
/* -> perpetual ~10Hz rebuild of #cards. A native click fires only if      */
/* mousedown & mouseup hit the SAME node; a rebuild between them cancels    */
/* the click -> "needs double/triple-click", search-result won't open,     */
/* can't switch results. FIX: (1) neutralize 0N's scheduled re-sorts via    */
/* _pps0N_reorderTimer intercept; (2) keep SNo order with an idempotent     */
/* sorter that re-appends ONLY when order is wrong (no-op when sorted ->     */
/* no mutation -> no loop). Idempotent redeploy. */
/* ====================================================================== */
(function(){
  window.SESSION_1B8_LOADED = true;
  var log = window._pps_origConsoleLog || console.log;

  if (window._pps1b8_obs) { try { window._pps1b8_obs.disconnect(); } catch(e){} }
  if (window._pps1b8_killer) { try { clearInterval(window._pps1b8_killer); } catch(e){} window._pps1b8_killer = null; }

  try { if (window._pps0N_reorderTimer) clearTimeout(window._pps0N_reorderTimer); } catch(e){}

  var neutralized = false;
  try {
    Object.defineProperty(window, '_pps0N_reorderTimer', {
      configurable: true,
      get: function(){ return null; },
      set: function(v){ if (v) { try { clearTimeout(v); } catch(e){} } }
    });
    neutralized = true;
  } catch(e) {
    window._pps1b8_killer = setInterval(function(){
      if (window._pps0N_reorderTimer) {
        try { clearTimeout(window._pps0N_reorderTimer); } catch(e2){}
        try { window._pps0N_reorderTimer = null; } catch(e2){}
      }
    }, 40);
  }

  function isSorted(wrapper){
    var cards = wrapper.querySelectorAll('.card[data-sno]');
    var prev = -Infinity;
    for (var i = 0; i < cards.length; i++){
      var s = parseInt(cards[i].getAttribute('data-sno'), 10);
      if (isNaN(s)) s = 0;
      if (s < prev) return false;
      prev = s;
    }
    return true;
  }

  function idempotentSort(){
    var wrapper = document.getElementById('cards');
    if (!wrapper) return;
    if (isSorted(wrapper)) return;
    var cards = Array.prototype.slice.call(wrapper.querySelectorAll('.card'));
    if (cards.length < 2) return;
    cards.sort(function(a, b){
      var sa = parseInt(a.getAttribute('data-sno'), 10); if (isNaN(sa)) sa = 0;
      var sb = parseInt(b.getAttribute('data-sno'), 10); if (isNaN(sb)) sb = 0;
      return sa - sb;
    });
    var frag = document.createDocumentFragment();
    cards.forEach(function(c){ frag.appendChild(c); });
    wrapper.appendChild(frag);
  }

  var wrapper = document.getElementById('cards');
  if (wrapper) {
    var t = null;
    var obs = new MutationObserver(function(muts){
      var childChange = false;
      for (var i = 0; i < muts.length; i++){ if (muts[i].type === 'childList'){ childChange = true; break; } }
      if (!childChange) return;
      if (isSorted(wrapper)) return;
      if (t) clearTimeout(t);
      t = setTimeout(idempotentSort, 120);
    });
    obs.observe(wrapper, { childList: true });
    window._pps1b8_obs = obs;
    setTimeout(idempotentSort, 150);
  }

  log.call(console, '[Session 1B.8] Session 0N loop ' + (neutralized ? 'neutralized (property intercept)' : 'neutralized (interval fallback)') + '; idempotent SNo sort active. #cards stable between clicks.');
})();


