  // ---------- #221 Thiruvathigai Veerattaneswarar — TRIPURA SAMHARA ----------
  var tv_en = "The Veerattaneswarar Temple at Thiruvathigai, 2 km from Panruti in Cuddalore district on the north bank of the Kedilam river, is one of the eight ATTA VEERATTANAM temples and a Paadal Petra Sthalam sung by all three Moovar. It enshrines the TRIPURA SAMHARA: Shiva's destruction of the three flying fortress-cities (Tripura) of gold, silver, and iron built by the asuras Vidyunmali, Tarakaksha, and Kamalaksha. When the three demons oppressed the worlds, Shiva made the earth his chariot, the four Vedas his horses, Brahma his charioteer, Mount Meru his bow, Vasuki the bowstring, and Vishnu the arrow — but as the devas grew proud, imagining the victory owed to their aid, Shiva simply SMILED, and in that smile (the 'fiery laugh') the three cities were reduced to ash. He dipped three fingers in the ashes, giving Shaivites the three horizontal lines of vibhuti worn on the brow. Shiva is worshipped here as Tripurantaka / Veerattaneswarar, a large swayambhu lingam with sixteen facets; his consort is Tripurasundari (Periyanayaki). Uniquely, the temple is built in the SHAPE OF A CHARIOT, and it was here, tradition holds, that the practice of breaking the three-eyed 'soorai' coconut before Ganesha began, when the slighted Vinayaka broke the chariot's axle. Above all, Thiruvathigai is the shrine of APPAR'S RECONVERSION: the saint, born Marulneekkiyar and turned to Jainism as Dharmasena, was struck by an incurable colic (soolai); his devoted sister Tilakavathiyar brought him here, smeared him with sacred ash, and he was cured — singing the 'Kootrayinavaaru' padigam, receiving the name Thirunavukkarasar ('king of the tongue'), and returning forever to Shaivism. The Kedilam river (the 'Ganga of the South'), the Sarakkonrai sthala-vriksha, and the Soola Theertham complete the sacred site, administered by the Thiruvavaduthurai Aadheenam. Pilgrims come to shed ego and pride, which dissolve — like the three cities — in the smile of Shiva.";
  var tv_ta = "கடலூர் மாவட்டத்தில், பன்ருட்டியிலிருந்து 2 கி.மீ., கெடிலம் நதியின் வட கரையில் அமைந்துள்ள திருவதிகை வீரட்டானேஸ்வரர் திருக்கோயில், எட்டு அட்ட வீரட்டானம் கோயில்களில் ஒன்று, மூன்று மூவரும் பாடிய பாடல் பெற்ற தலம். இது திரிபுர சம்ஹாரத்தை — வித்யுன்மாலி, தாருகாக்ஷன், கமலாக்ஷன் என்ற அசுரர்கள் கட்டிய பொன், வெள்ளி, இரும்பு பறக்கும் முப்புர கோட்டைகளை ஶிவன் அழித்ததை — பொதிந்துள்ளது. மூன்று அசுரர்கள் உலகங்களைத் துன்புறுத்தியபோது, ஶிவன் பூமியைத் தேராக்கி, நான்கு வேதங்களைக் குதிரைகளாக்கி, பிரம்மாவை சாரதியாக்கி, மேருமலையை வில்லாக்கி, வாசுகியை நாணாக்கி, விஷ்ணுவை அம்பாக்கினார் — ஆனால் தேவர்கள் தங்கள் உதவியால்தான் வெற்றி என்று கர்வம் கொண்டபோது, ஶிவன் வெறுமனே புன்னகைத்தார், அந்த புன்னகையில் மூன்று கோட்டைகளும் சாம்பலாயின. அவர் மூன்று விரல்களை சாம்பலில் தோய்த்து, ஶைவர்கள் நெற்றியில் அணியும் மூன்று விபூதிக் கோடுகளை அளித்தார். ஶிவன் இங்கே திரிபுராந்தகர் / வீரட்டானேஸ்வரராக, பதினாறு பட்டைகள் கொண்ட பெரிய சுயம்பு லிங்கமாக வழிபடப்படுகிறார்; துணை திரிபுரசுந்தரி (பெரியநாயகி). கோயில் தேர் வடிவில் கட்டப்பட்டுள்ளது, மற்றும் விநாயகருக்கு முன் மூன்று-கண் சூரைக்காய் உடைக்கும் பழக்கம் இங்கே தொடங்கியது. எல்லாவற்றுக்கும் மேலாக, திருவதிகை அப்பரின் மறுமலர்ச்சியின் சந்நிதி: மருள்நீக்கியாராகப் பிறந்து சமணராக மாறிய தர்மசேனர், குணமாகா சூலை நோயால் பீடிக்கப்பட்டார்; அவரது சகோதரி திலகவதியார் அவரை இங்கே அழைத்து வந்து திருநீறு பூச, அவர் குணமாகி 'கூற்றாயினவாறு' பதிகம் பாடி, திருநாவுக்கரசர் என்ற பெயர் பெற்று, என்றென்றும் ஶைவத்திற்குத் திரும்பினார். கெடிலம் நதி (தென் கங்கை), சரக்கொன்றை ஸ்தல-விருக்ஷம், சூல தீர்த்தம் புனித தளத்தை நிறைவு செய்கின்றன.";
  window.TEMPLE_ENRICHMENT[221] = {
    content_tier: 'T1', categories: ['atta_veerattanam','nayanmar_birthplace_63'],
    sthala_purana_en: tv_en, sthala_purana_ta: tv_ta,
    goddess_en: "Tripurasundari (Periyanayaki, also Mookambigai) — consort of Veerattaneswarar, worshipped in a prominent shrine; a powerful Shakta form invoked alongside the Tripura-conquering Lord.",
    goddess_ta: "திரிபுரசுந்தரி (பெரியநாயகி, மூகாம்பிகை) — வீரட்டானேஸ்வரரின் துணை, முக்கிய சந்நிதியில் வழிபடப்படுகிறாள்; முப்புரம் வென்ற இறைவனுடன் வேண்டப்படும் சக்திவாய்ந்த ஶாக்த வடிவம்.",
    pushkarini_en: "Soola Theertham and the Kedilam river — the 'Ganga of the South,' on whose north bank the chariot-shaped temple stands.",
    pushkarini_ta: "சூல தீர்த்தம் மற்றும் கெடிலம் நதி — 'தென் கங்கை,' அதன் வட கரையில் தேர்-வடிவ கோயில் நிற்கிறது.",
    sthala_vriksha: { common_name_en: "Sarakkonrai (Golden Shower)", common_name_ta: "சரக்கொன்றை", scientific_name: "Cassia fistula",
      description_en: "The Sthala Vriksha is Sarakkonrai (Cassia fistula), the golden-flowered Konrai sacred to Shiva, whose blossoms adorn his matted locks.",
      description_ta: "ஸ்தல விருக்ஷம் சரக்கொன்றை (Cassia fistula), ஶிவனுக்கு புனிதமான தங்க-மலர் கொன்றை, அதன் மலர்கள் அவரது சடையை அலங்கரிக்கின்றன.",
      significance_en: "The Konrai, foremost flower of Shiva, is apt for the shrine of Tripurantaka and Appar's redemption.",
      significance_ta: "ஶிவனின் முதன்மை மலரான கொன்றை, திரிபுராந்தகர் மற்றும் அப்பரின் மீட்பின் சந்நிதிக்குப் பொருந்துகிறது." },
    festivals_en: ["Appar Salvation festival / Chithirai Sadayam (Apr-May) — commemorating Thirunavukkarasar","Maha Shivaratri (Feb-Mar)","Vaikasi Brahmotsavam (May-Jun)","Aadi Pooram; Margazhi Tiruvadhirai","Manickavasagar Utsavam (Margazhi)"],
    festivals_ta: ["அப்பர் முக்தி விழா / சித்திரை சதயம் (சித்திரை-வைகாசி) — திருநாவுக்கரசரை நினைவுகூர்தல்","மகா ஶிவராத்திரி (மாசி)","வைகாசி பிரம்மோற்சவம்","ஆடிப்பூரம்; மார்கழி திருவாதிரை","மாணிக்கவாசகர் உற்சவம் (மார்கழி)"],
    town_ta: "திருவதிகை", coords_verified: true,
    naalvar_present: ["sambandar","appar","sundarar"],
    nayanmar_associations: [
      { nayanmar: "appar", role: "reconversion_site", brief_en: "Appar was cured of soolai and reconverted to Shaivism here, gaining the name Thirunavukkarasar", brief_ta: "அப்பர் சூலை நோய் நீங்கி இங்கே ஶைவத்திற்குத் திரும்பி திருநாவுக்கரசர் பெயர் பெற்றார்",
        story_en: "Thiruvathigai is the site of Appar's reconversion. Born Marulneekkiyar, he had turned to Jainism as Dharmasena; struck by an incurable colic, his sister Tilakavathiyar brought him to Thiruvathigai, applied the sacred ash, and he was cured. He sang the 'Kootrayinavaaru' padigam, was named Thirunavukkarasar by Shiva himself, and returned to Shaivism forever. He later performed uzhavaarap-pani (temple-cleaning service) here. Thiruvathigai is thus one of the most pivotal sites in the Nayanar tradition.",
        story_ta: "திருவதிகை அப்பரின் மறுமலர்ச்சியின் தளம். மருள்நீக்கியாராகப் பிறந்து சமணராக (தர்மசேனர்) மாறிய அவர், குணமாகா சூலை நோயால் பீடிக்கப்பட்டபோது, சகோதரி திலகவதியார் அவரை திருவதிகைக்கு அழைத்து வந்து திருநீறு பூச, அவர் குணமானார். 'கூற்றாயினவாறு' பதிகம் பாடி, ஶிவனாலேயே திருநாவுக்கரசர் என்று பெயரிடப்பட்டு, என்றென்றும் ஶைவத்திற்குத் திரும்பினார்." },
      { nayanmar: "tilakavathiyar", role: "devotee", brief_en: "Tilakavathiyar, Appar's sister, whose devotion brought him back to Shiva", brief_ta: "திலகவதியார், அப்பரின் சகோதரி, யாருடைய பக்தி அவரை ஶிவனிடம் மீட்டது",
        story_en: "Tilakavathiyar, the elder sister of Appar, was an ardent Shiva devotee who dedicated her life to service at Thiruvathigai after her betrothed died. Her ceaseless prayer for her brother's return to Shaivism was answered when Shiva afflicted him with colic and drew him back; she applied the sacred ash that cured him. She is honoured among the great women of the Shaiva tradition.",
        story_ta: "அப்பரின் தமக்கையார் திலகவதியார், தமது வருங்கால கணவர் இறந்தபின் திருவதிகையில் திருத்தொண்டு செய்த தீவிர ஶிவ பக்தை. தமது தம்பி ஶைவத்திற்குத் திரும்ப அவரது இடையறா வேண்டுதல் நிறைவேறியது." }
    ],
    cross_tradition_en: [
      { tradition: "atta_veerattanam", story: "Thiruvathigai is the TRIPURA SAMHARA shrine of the eight Atta Veerattanam — where Shiva burned the three flying cities of the asuras with a mere smile, teaching the devas that victory owes to grace alone, not their aid. From the ashes came the three lines of vibhuti. Shiva is Tripurantaka; the chariot-shaped temple embodies the cosmic war-chariot. Pilgrims come to dissolve ego and pride." },
      { tradition: "nayanmar_birthplace_63", story: "Thiruvathigai is the pivotal site of Appar's (Thirunavukkarasar's) reconversion from Jainism to Shaivism — cured of colic by his sister Tilakavathiyar's sacred ash, singing the Kootrayinavaaru, and named 'king of the tongue' by Shiva. It is among the most important biographical shrines of the 63 Nayanmars." },
      { tradition: "other", story: "Built in the shape of a chariot on the north bank of the Kedilam ('Ganga of the South'), Thiruvathigai is where the custom of breaking the three-eyed soorai coconut before Ganesha is said to have originated (when Vinayaka broke the war-chariot's axle). A pre-7th-century foundation with Pallava and Chola patronage, administered by the Thiruvavaduthurai Aadheenam." }
    ],
    cross_tradition_ta: [
      { tradition: "atta_veerattanam", story: "திருவதிகை எட்டு அட்ட வீரட்டானத்தின் திரிபுர சம்ஹார சந்நிதி — ஶிவன் அசுரர்களின் மூன்று பறக்கும் கோட்டைகளை வெறும் புன்னகையால் எரித்து, வெற்றி அருளால் மட்டுமே என்று தேவர்களுக்கு உணர்த்திய இடம். சாம்பலிலிருந்து மூன்று விபூதிக் கோடுகள் வந்தன. ஶிவன் திரிபுராந்தகர்; தேர்-வடிவ கோயில் பிரபஞ்ச போர்-தேரை உருவகிக்கிறது." },
      { tradition: "nayanmar_birthplace_63", story: "திருவதிகை அப்பரின் (திருநாவுக்கரசரின்) சமணத்திலிருந்து ஶைவத்திற்கான மறுமலர்ச்சியின் முக்கிய தளம் — சகோதரி திலகவதியாரின் திருநீற்றால் சூலை குணமாகி, கூற்றாயினவாறு பாடி, ஶிவனால் 'நாவுக்கரசர்' எனப் பெயரிடப்பட்டார். 63 நாயன்மார்களின் மிக முக்கிய வாழ்க்கை சந்நிதிகளில் ஒன்று." },
      { tradition: "other", story: "கெடிலம் நதியின் (தென் கங்கை) வட கரையில் தேர் வடிவில் கட்டப்பட்ட திருவதிகை, விநாயகருக்கு முன் மூன்று-கண் சூரைக்காய் உடைக்கும் பழக்கம் தொடங்கிய இடம். 7-ம் நூற்றாண்டுக்கு முந்தைய அமைப்பு, திருவாவடுதுறை ஆதீனத்தால் நிர்வகிக்கப்படுகிறது." }
    ]
  };

  // ---------- #230 Thirukovilur Veerateeswarar — ANDHAKASURA SAMHARA ----------
  var tk_en = "The Veerateeswarar Temple at Thirukovilur (Tirukoilur), on the banks of the South Pennai (Thenpennai) river in Kallakurichi district, is one of the eight ATTA VEERATTANAM temples and a Paadal Petra Sthalam sung by all three Moovar. It enshrines the ANDHAKASURA SAMHARA. The demon Andhaka ('darkness / ignorance') was born when Parvati playfully covered Shiva's eyes — the sun and moon — plunging the cosmos into darkness; the sweat of that darkness took demonic form. Andhaka, granted near-immortality by Brahma with the sole condition that he would die if he lusted after his own mother, misused his power and finally lusted after Parvati herself — who was as his mother. Shiva appeared as Andhakasura-samhara-murti and impaled him on his trident; but each drop of the demon's blood that touched the earth spawned a new demon, so Parvati collected the blood in a bowl. The drops that escaped formed 64 squares, from each of which Shiva manifested a Bhairava — the origin of the 64 Bhairavas and the Vasthu Shanti tradition. Realising his sin, Andhaka begged to be reborn as Shiva's devotee, and was granted rebirth as Gana Bhringi. Shiva is Veerateeswarar (swayambhu, with Bhairava power); his consort is Periyanayaki (Sivanandavalli). Thirukovilur is of great antiquity, praised in Sangam literature (Agananuru, Purananuru) and linked to the charitable Malaiyaman chieftains; it was here that the poetess AVVAIYAR sang her celebrated Vinayagar Agaval. Devotees come to conquer the inner 'darkness' of ignorance and ego, and for relief from black magic; the temple is the 11th Nadunadu Tevara Stalam and administered by the Tamil Nadu HR&CE.";
  var tk_ta = "கள்ளக்குறிச்சி மாவட்டத்தில், தென்பெண்ணை நதிக் கரையில் அமைந்துள்ள திருக்கோவிலூர் வீரட்டேஸ்வரர் திருக்கோயில், எட்டு அட்ட வீரட்டானம் கோயில்களில் ஒன்று, மூன்று மூவரும் பாடிய பாடல் பெற்ற தலம். இது அந்தகாசுர சம்ஹாரத்தை பொதிந்துள்ளது. பார்வதி விளையாட்டாக ஶிவனின் கண்களை — சூரியனையும் சந்திரனையும் — மூடியபோது பிரபஞ்சம் இருளில் மூழ்கி, அந்த இருளின் வியர்வை அசுர வடிவம் எடுத்தபோது அந்தகன் ('இருள்/அறியாமை') பிறந்தான். தன் தாயை மோகித்தால் மட்டுமே இறப்பான் என்ற ஒரே நிபந்தனையுடன் பிரம்மாவால் கிட்டத்தட்ட அமரத்துவம் அளிக்கப்பட்ட அந்தகன், தன் சக்தியைத் தவறாகப் பயன்படுத்தி இறுதியில் தாய் போன்ற பார்வதியையே மோகித்தான். ஶிவன் அந்தகாசுர-சம்ஹார-மூர்த்தியாகத் தோன்றி அவனைத் திரிசூலத்தில் கோத்தார்; ஆனால் அசுரனின் ஒவ்வொரு இரத்தத் துளியும் பூமியில் பட்டு புதிய அசுரனை உருவாக்கியதால், பார்வதி இரத்தத்தை ஒரு கிண்ணத்தில் சேகரித்தாள். தப்பிய துளிகள் 64 சதுரங்களை உருவாக்க, ஒவ்வொன்றிலிருந்தும் ஶிவன் ஒரு பைரவரை வெளிப்படுத்தினார் — 64 பைரவர்கள் மற்றும் வாஸ்து சாந்தி மரபின் தோற்றம். எனவே ஶிவன் வீரட்டேஸ்வரர் (சுயம்பு, பைரவ சக்தியுடன்); துணை பெரியநாயகி (சிவநந்தவல்லி). திருக்கோவிலூர் மிகப் பழமையானது, சங்க இலக்கியத்தில் (அகநானூறு, புறநானூறு) போற்றப்படுகிறது; அவ்வையார் தமது புகழ்பெற்ற விநாயகர் அகவலை இங்கே பாடினார்.";
