    festivals_en: ["Tula Snanam / Aippasi Tula month (Oct-Nov) — the supreme Kaveri-bathing festival, culminating on Tula Amavasya","Maha Shivaratri","Aadi Pooram (Abhayambikai)","Navaratri","Chithirai Brahmotsavam; Arudra Darshan"],
    festivals_ta: ["துலா ஸ்நானம் / ஐப்பசி துலா மாதம் (ஐப்பசி) — உச்ச காவேரி-நீராடு விழா, துலா அமாவாசையில் உச்சம்","மகா ஶிவராத்திரி","ஆடிப்பூரம் (அபயாம்பிகை)","நவராத்திரி","சித்திரை பிரம்மோற்சவம்; ஆருத்ரா தரிசனம்"],
    town_ta: "மயிலாடுதுறை", coords_verified: true,
    naalvar_present: ["sambandar","appar","sundarar"],
    nayanmar_associations: [
      { nayanmar: "sambandar", role: "pilgrim_poet", brief_en: "All three Moovar sang Mayuranathar; Vayilar Nayanar was born here", brief_ta: "மூவரும் மயூரநாதரைப் பாடினர்; வாயிலார் நாயனார் இங்கே பிறந்தார்",
        story_en: "Sambandar, Appar, and Sundarar all sang Mayuranathar of Mayiladuthurai. The town is also the birthplace of Vayilar Nayanar, one of the 63 Nayanmars, who worshipped Shiva in the temple of his own heart — one of the most contemplative figures of the Periya Puranam.",
        story_ta: "சம்பந்தர், அப்பர், சுந்தரர் மூவரும் மயிலாடுதுறை மயூரநாதரைப் பாடினர். நகரம் 63 நாயன்மார்களில் ஒருவரான வாயிலார் நாயனாரின் பிறப்பிடமும் ஆகும், அவர் தமது இதயக் கோயிலில் ஶிவனை வழிபட்டார்." }
    ],
    cross_tradition_en: [
      { tradition: "kashi_equivalent", story: "Mayiladuthurai is among the foremost KASHI-EQUIVALENT kshetrams of the Kaveri: on Tula Amavasya (Aippasi), all the sacred rivers of India, and the Ganga herself, are believed to gather in the Kaveri here — the Ganga coming annually to cleanse the sins she has absorbed — so a bath here that day equals bathing in the Ganga at Kashi, drawing enormous Tula-Snanam crowds." },
      { tradition: "shakta", story: "The founding legend is Parvati's peahen-penance: cursed to a peahen's (mayil) form, she did penance on the Kaveri and was restored by Shiva, giving Mayiladuthurai ('the landing where the peahen worshipped') its name and the Lord his epithet Mayuranathar; the Goddess Abhayambikai is worshipped for protection and grace." },
      { tradition: "nayanmar_birthplace_63", story: "Mayiladuthurai is the birthplace of Vayilar Nayanar, one of the 63 Nayanmars, and a central node of the Kaveri-delta pilgrimage near Vaitheeswaran Koil, Sirkazhi, and the Navagraha temples; administered by the Dharmapuram Aadheenam." }
    ],
    cross_tradition_ta: [
      { tradition: "kashi_equivalent", story: "மயிலாடுதுறை காவேரியின் தலைசிறந்த காசி-இணை க்ஷேத்திரங்களில் ஒன்று: துலா அமாவாசையில் (ஐப்பசி) இந்தியாவின் அனைத்து புனித நதிகளும் கங்கையும் இங்கே காவேரியில் கூடுவதாக நம்பப்படுகிறது — கங்கை ஆண்டுதோறும் தான் உறிஞ்சிய பாவங்களைக் கழுவ வருகிறாள் — எனவே அந்நாள் நீராடல் காசியில் கங்கை நீராடலுக்குச் சமம்." },
      { tradition: "shakta", story: "ஸ்தாபன தொன்மம் பார்வதியின் மயில்-தவம்: மயில் வடிவெடுக்கச் சபிக்கப்பட்டு, காவேரியில் தவம் புரிந்து ஶிவனால் மீட்கப்பட்டாள், மயிலாடுதுறைக்கு ('மயில் வழிபட்ட துறை') பெயரிட்டாள்." },
      { tradition: "nayanmar_birthplace_63", story: "மயிலாடுதுறை 63 நாயன்மார்களில் ஒருவரான வாயிலார் நாயனாரின் பிறப்பிடம், வைத்தீஶ்வரன் கோயில், சீர்காழி, நவகிரக கோயில்களுக்கு அருகில் காவேரி-டெல்டா யாத்திரையின் மைய முனை." }
    ]
